// Generic class
public class Box<T> {
    private T value;
    public Box(T value) { this.value = value; }
    public T get() { return value; }
}

Box<String> strBox = new Box<>("hello");
String s = strBox.get();  // no cast needed — type-safe

// Raw type — avoid!
Box rawBox = new Box("hello");  // compiler warning
String bad = (String) rawBox.get();  // cast required, can blow up

// Generic method
public static <T extends Comparable<T>> T max(T a, T b) {
    return a.compareTo(b) >= 0 ? a : b;
}

int bigger = max(3, 7);      // T inferred as Integer
String later = max("apple", "banana"); // T inferred as String

// Producer Extends — read-only, upper bounded
public static double sumList(List<? extends Number> list) {
    double sum = 0;
    for (Number n : list) sum += n.doubleValue(); // can read as Number
    // list.add(3.14); // COMPILE ERROR — can't write (type unknown)
    return sum;
}
sumList(List.of(1, 2, 3));       // List<Integer> OK
sumList(List.of(1.5, 2.5));      // List<Double> OK

// Consumer Super — write-only, lower bounded
public static void addNumbers(List<? super Integer> list) {
    list.add(1); list.add(2);     // can write Integer
    // Integer n = list.get(0);  // COMPILE ERROR — returns Object
}
List<Number> nums = new ArrayList<>();
addNumbers(nums);                 // List<Number> accepts Integer writes

