// Illegal — type info erased at runtime
if (obj instanceof List<String>) { }  // COMPILE ERROR

// Legal — raw type check (loses generic safety)
if (obj instanceof List<?>) { }  // OK, unbounded wildcard

// Generic array creation is illegal
// T[] arr = new T[10];  // COMPILE ERROR
// Workaround:
@SuppressWarnings("unchecked")
T[] arr = (T[]) new Object[10];  // unchecked cast, may cause heap pollution

// Bridge methods: compiler generates these for generic subclasses
class MyList extends ArrayList<String> {
    @Override
    public boolean add(String s) { return super.add(s); }
    // Compiler also generates: add(Object o) { add((String)o); }
    // This bridges the erased supertype's add(Object) to our add(String)
}

// @SafeVarargs suppresses heap pollution warnings for generic varargs
@SafeVarargs
public static <T> List<T> listOf(T... items) {
    return Arrays.asList(items);
}

// Multiple bounds — class first, then interfaces
public static <T extends Number & Comparable<T>> T clamp(
        T value, T min, T max) {
    if (value.compareTo(min) < 0) return min;
    if (value.compareTo(max) > 0) return max;
    return value;
}

int result = clamp(15, 0, 10);   // T=Integer, returns 10

// Generic static utility method
public static <T> Optional<T> firstMatch(
        List<T> list, Predicate<T> pred) {
    return list.stream().filter(pred).findFirst();
}

Optional<String> found = firstMatch(names, s -> s.startsWith("A"));

// Explicit type witness (rarely needed — helps when inference fails)
List<String> empty = Collections.<String>emptyList();
// Modern Java usually infers correctly without the witness

// F-bounded type: ensures type safety in self-referential hierarchies
public static <T extends Comparable<T>> T max(List<T> list) {
    return list.stream().max(Comparator.naturalOrder()).orElseThrow();
}
// max(List<Integer>) returns Integer, not Comparable
// max(List<String>) returns String, not Comparable

// Builder pattern with F-bounded type for fluent subclass chaining
public abstract class Builder<T extends Builder<T>> {
    protected String name;
    @SuppressWarnings("unchecked")
    public T name(String name) { this.name = name; return (T) this; }
    public abstract Product build();
}

public class CarBuilder extends Builder<CarBuilder> {
    private int wheels;
    public CarBuilder wheels(int n) { this.wheels = n; return this; }
    public Car build() { return new Car(name, wheels); }
}

// Chaining returns CarBuilder, not Builder — no cast needed
Car c = new CarBuilder().name("Tesla").wheels(4).build();

